effect.shader:
#define MULTISAMPLE 1.0
#define MAX_RADIUS 16383.0

vec2 encodeFloat(float v) {
    highp vec2 enc = fract(vec2(1.0, 255.0)*v);
    enc.x -= enc.y/255.0;
    return enc;
}

float decodeFloat(vec2 v) {
    return dot(v,vec2(1.0,1.0/255.0));
}

struct Border {
    int direction;
    float size;
    vec4 color;
};

void main() {

    float radius=maxsize*MULTISAMPLE;

    int from = -max(1,int(radius));
    int to = max(1,int(radius));

    // Size of a pixel
    float px = 1.0 / 2048.0;
    vec2 fullViewSize = getTexSize(inputImg.size);
    float py = 1.0 / (2048.0 / (fullViewSize.x/fullViewSize.y));

    if( acPass==0 ) {

        // Calculate distance on X-axis and encode in a texture

        float nearestOutside = MAX_RADIUS;
        float nearestInside = MAX_RADIUS;

        for(int i=from; i<to; i++ ) {

            float x = float(i);

            vec4 sample = texture2DCv(inputImg.texture,vec2(acScreenNorm.s + x*(px/MULTISAMPLE),acScreenNorm.t));
            float xdistOut = sample.a > 0.0 ? abs(x) : radius*2.0;
            float xdistIn = sample.a < 0.003 ? abs(x) : radius*2.0;
            nearestOutside = min(nearestOutside,xdistOut);
            nearestInside = min(nearestInside,xdistIn);

        }

        gl_FragColor = vec4(encodeFloat(nearestOutside/MAX_RADIUS),encodeFloat(nearestInside/MAX_RADIUS));

    } else {

        // Final pass

        float nearestOutside = MAX_RADIUS;
        float nearestInside = MAX_RADIUS;

        for(int i=from; i<to; i++ ) {

            float y = float(i);

            vec4 sample = texture2DCv(xDistBuf.texture,vec2(acScreenNorm.s,acScreenNorm.t + y*(py/MULTISAMPLE)));

            float xdistOut = decodeFloat(sample.rg) * MAX_RADIUS;
            float xdistIn = decodeFloat(sample.ba) * MAX_RADIUS;
            float ydist = abs(y);
            float distOut = length(vec2(xdistOut,ydist));
            float distIn = length(vec2(xdistIn,ydist));

            nearestInside = min(nearestInside,distIn);
            nearestOutside = min(nearestOutside,distOut);
        }

        float nearestMid = max(nearestInside, nearestOutside);

        vec4 original = texture2DCv(inputImg.texture,acScreenNorm.st);

        vec4 result = original;

        int direction;
        vec4 color;
        float size;

        // 0
        direction = b0direction;
        color = b0color;
        size = b0size;
        if( size > 0.003 ) {
            if( direction == -1 ) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestInside/(size/MULTISAMPLE))) * original.a;
                result = c + result*(1.0-c.a);
            } else if (direction == 0) {
                vec4 c = mix(color, vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestMid/(size/MULTISAMPLE)));;
                result = c + result*(1.0-c.a);
            } else if (direction == 1) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestOutside/(size/MULTISAMPLE))) * (1.-original.a);
                result = result + c*(1.0-result.a);
            }
        }

        // 1
        direction = b1direction;
        color = b1color;
        size = b1size;
        if( size > 0.003 ) {
            if( direction == -1 ) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestInside/(size/MULTISAMPLE))) * original.a;
                result = c + result*(1.0-c.a);
            } else if (direction == 0) {
                vec4 c = mix(color, vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestMid/(size/MULTISAMPLE)));;
                result = c + result*(1.0-c.a);
            } else if (direction == 1) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestOutside/(size/MULTISAMPLE))) * (1.-original.a);
                result = result + c*(1.0-result.a);
            }
        }

        // 2
        direction = b2direction;
        color = b2color;
        size = b2size;
        if( size > 0.003 ) {
            if( direction == -1 ) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestInside/(size/MULTISAMPLE))) * original.a;
                result = c + result*(1.0-c.a);
            } else if (direction == 0) {
                vec4 c = mix(color, vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestMid/(size/MULTISAMPLE)));;
                result = c + result*(1.0-c.a);
            } else if (direction == 1) {
                vec4 c = mix(color,  vec4(0.0), smoothstep(1.0-1.5/size,1.0,nearestOutside/(size/MULTISAMPLE))) * (1.-original.a);
                result = result + c*(1.0-result.a);
            }
        }

        gl_FragColor = result;
    }
}
